import sys
from typing import List

class Solution:
    def solve(self, nums: List[int]) -> int:
        stk = []
        count = 0
        for num in nums:
            if num % 2 == 0: count += 1
            # push num into stack
            if num % 2 != 0: stk.append(num)
        return len(stk)



if __name__ == '__main__':
    s = Solution()
    nums = list(map(int, input().split()))
    print(s.solve(nums))

