#include <iostream>
#include <stack>
#include <vector>
using namespace std;

bool solve(vector<int>& nums) {
    stack<int> stk;
    int count = 0;
    for (int num : nums) {
        if (num % 2 == 0) { count++; }
        stk.push(num);
    }
    return stk.size();
}

int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) {
        cin >> nums[i];
    }
    cout << solve(nums) << endl;
    return 0;
}
